mapper.select:
SELECT if(#{contractType} = 'B',b.id,s.id) id,
       if(#{contractType} = 'B',b.contract_no,s.contract_no) contractNo,
       if(#{contractType} = 'B',b.contract_type,s.contract_type) contractType,
	   if(#{contractType} = 'B',b.business_type_dcsx,s.business_type_dcsx) businessTypeDcsx,
	   if(#{contractType} = 'B',b.products_name,s.products_name) productsName,
	   if(#{contractType} = 'B',b.company_name,s.company_name) companyName,
	   if(#{contractType} = 'B',b.total_number,s.total_number) totalNumber,
	   if(#{contractType} = 'B',b.total_amount,s.total_amount) totalAmount,
	   if(#{contractType} = 'B',b.warehouse_number,s.warehouse_number) warehouseNumber,
	   if(#{contractType} = 'B',b.delivery_date_from,s.delivery_date_from) deliveryDateFrom,
	   if(#{contractType} = 'B',b.match_user_name,s.match_user_name) matchUserName,
	   if(#{contractType} = 'B',b.approve_id,s.approve_id) approveId,
	   if(#{contractType} = 'B',b.apply_cancel_flg,s.apply_cancel_flg) applyCancelFlg,
       b.match_credit_flg matchCreditFlg

FROM t_ctr_contract b
INNER JOIN t_ctr_contract_rela r ON r.buy_contract_id=b.id
INNER JOIN t_ctr_contract s ON r.sell_contract_id=s.id
WHERE 1=1

	AND b.enterprise_id = 44
	AND b.STATUS != 'C'
	AND b.contract_type = #{contractType}

		AND b.match_credit_flg = #{matchCreditFlg}



		AND b.contract_no LIKE "%"#{contractNo}"%"


		AND b.company_name LIKE "%"#{companyName}"%"


		AND b.our_company_name LIKE "%"#{ourCompanyName}"%"


		AND #{deliveryDateTo} >=  DATE_FORMAT(b.delivery_date_to,'%Y-%m-%d')


		AND DATE_FORMAT(b.delivery_date_to,'%Y-%m-%d') >= #{deliveryDateFrom}



	AND s.enterprise_id = 44
	AND s.STATUS != 'C'
	AND s.contract_type = #{contractType}

		AND s.match_credit_flg = #{matchCreditFlg}



		AND s.contract_no LIKE "%"#{contractNo}"%"


		AND s.company_name LIKE "%"#{companyName}"%"


		AND s.our_company_name LIKE "%"#{ourCompanyName}"%"


		AND #{deliveryDateTo} >=  DATE_FORMAT(s.delivery_date_to,'%Y-%m-%d')


		AND DATE_FORMAT(s.delivery_date_to,'%Y-%m-%d') >= #{deliveryDateFrom}




	AND b.warehouse_number >= b.total_number


	AND b.total_number > b.warehouse_number



	AND s.warehouse_number >= s.total_number


	AND s.total_number > s.warehouse_number



	AND b.dealed_amount >= b.total_amount


	AND b.total_amount > b.dealed_amount


	and s.match_user_id not in

		#{hgMatchUserIdList[${index}]}



	and s.match_user_id in

		#{hgMatchUserIdList[${index}]}


 order by b.id desc
